field.eval:
{
                'code': 'projects.list',
                'name': '项目台账',
                'version': 'v2',
                'page': {
                    'key': 'projects.list.main',
                    'title': '项目台账',
                    'page_type': 'list',
                    'page_mode': 'table'
                },
                'layout': {'kind': 'list', 'sidebar': 'fixed', 'header': 'full'},
                'zone_blocks': [
                    {
                        'key': 'toolbar',
                        'title': '快捷入口',
                        'zone_type': 'hero',
                        'display_mode': 'stack',
                        'block_key': 'block.projects.list.toolbar'
                    },
                    {
                        'key': 'list_main',
                        'title': '项目清单',
                        'zone_type': 'primary',
                        'display_mode': 'table',
                        'block_key': 'block.projects.list.table'
                    },
                    {
                        'key': 'insight',
                        'title': '列表洞察',
                        'zone_type': 'supporting',
                        'display_mode': 'stack',
                        'block_key': 'block.projects.list.insight'
                    }
                ],
                'target': {
                    'route': '/s/projects.list',
                    'menu_xmlid': 'smart_construction_core.menu_sc_project_project',
                    'action_xmlid': 'smart_construction_core.action_sc_project_list'
                },
                'list_profile': {
                    'model': 'project.project',
                    'view_type': 'list',
                    'columns': [
                        'name',
                        'project_code',
                        'owner_id',
                        'sc_partner_display_name',
                        'operation_strategy',
                        'lifecycle_state',
                        'user_id',
                        'contract_amount',
                        'dashboard_progress_rate',
                        'write_date'
                    ],
                    'hidden_columns': [
                        'message_needaction',
                        'message_unread',
                        'is_favorite',
                        'display_name',
                        '__last_update'
                    ],
                    'column_labels': {
                        'name': '名称',
                        'project_code': '项目编号',
                        'owner_id': '业主单位',
                        'sc_partner_display_name': '关联单位',
                        'operation_strategy': '经营方式',
                        'lifecycle_state': '项目状态',
                        'user_id': '项目负责人',
                        'contract_amount': '合同总额',
                        'dashboard_progress_rate': '进度(%)',
                        'write_date': '更新时间'
                    },
                    'row_primary': 'name',
                    'row_secondary': ''
                },
                'action_specs': {
                    'open_intake': {
                        'label': '新建立项',
                        'intent': 'ui.contract'
                    },
                    'open_dashboard': {
                        'label': '进入项目驾驶舱',
                        'intent': 'ui.contract'
                    }
                },
                'role_variants': {
                    'pm': {
                        'default_actions': ['open_intake', 'open_dashboard'],
                        'focus_zones': ['list_main', 'insight']
                    },
                    'executive': {
                        'default_actions': ['open_dashboard'],
                        'focus_zones': ['toolbar', 'insight']
                    }
                },
                'data_sources': {
                    'project_list': {'source_type': 'odoo_model', 'model': 'project.project'},
                    'project_insight': {'source_type': 'computed', 'provider': 'projects.list.insight'}
                },
                'product_policy': {
                    'role_based': True,
                    'primary_action': 'open_intake',
                    'stage': 'wave2'
                },
                'related_scenes': [
                    'projects.intake',
                    'project.management',
                    'projects.ledger'
                ],
                'filters': [],
                'default_sort': 'write_date desc',
                'tiles': []
            }

